create policy project_members_select on public.project_members
for select
to authenticated
using (
  profile_id = auth.uid()
  or exists (
    select 1
    from public.projects p
    where p.id = project_id
      and p.owner_profile_id = auth.uid()
  )
  or public.project_role_for_profile(project_id, auth.uid()) = 'co_owner'
);

